export class OrderModule {}

// order.service.ts
import { Injectable } from '@nestjs/common';
import { ProductService } from '../products/product.service';
import { DiscountService } from '../discount/discount.service';
import { NotificationService } from '../notifications/notification.service';

@Injectable()
export class OrderService {
  constructor(
    private readonly productService: ProductService,
    private readonly discountService: DiscountService,
    private readonly notificationService: NotificationService,
  ) {}

  async createOrder(userId: string, productId: string, quantity: number) {
    const stockOk = await this.productService.checkStock(productId, quantity);
    if (!stockOk) throw new Error('Stock insuffisant');

    const discount = await this.discountService.getDiscount(userId);
    const total = quantity * 100; // prix exemple
    const finalTotal = total * (1 - discount / 100);

    await this.notificationService.sendEmail(userId, `Commande créée : ${finalTotal}€`);

    return { productId, quantity, discount, finalTotal };
  }
}
